class Solution:
    def splitArraySameAverage(self, nums):
        n = len(nums)
        total = sum(nums)
        # Brute force: try every non-empty proper subset, check equal averages.
        for mask in range(1, (1 << n) - 1):
            s = 0
            cnt = 0
            for i in range(n):
                if mask & (1 << i):
                    s += nums[i]
                    cnt += 1
            # average(A) == average(B) <=> s/cnt == (total-s)/(n-cnt)
            if s * (n - cnt) == (total - s) * cnt:
                return True
        return False

