class Solution:
    def splitArraySameAverage(self, nums):
        n = len(nums)
        total = sum(nums)
        # sums[k] = set of achievable sums using exactly k elements
        sums = [set() for _ in range(n // 2 + 1)]
        sums[0].add(0)
        for x in nums:
            for k in range(min(len(sums) - 1, n // 2), 0, -1):
                for prev in sums[k - 1]:
                    sums[k].add(prev + x)
        for k in range(1, n // 2 + 1):
            if total * k % n == 0:
                if (total * k) // n in sums[k]:
                    return True
        return False

