var splitArraySameAverage = function(nums) {
    const n = nums.length;
    const total = nums.reduce((a, b) => a + b, 0);
    const half = Math.floor(n / 2);
    const sums = Array.from({ length: half + 1 }, () => new Set());
    sums[0].add(0);
    for (const x of nums) {
        for (let k = Math.min(half, sums.length - 1); k >= 1; k--) {
            for (const prev of sums[k - 1]) sums[k].add(prev + x);
        }
    }
    for (let k = 1; k <= half; k++) {
        if ((total * k) % n === 0 && sums[k].has((total * k) / n)) return true;
    }
    return false;
};
